/**
 * Facade over ts-rs generated types.
 *
 * `types.generated.ts` is the source of truth (regenerated by
 * `cargo test` in src-tauri). This file re-exports everything from there and
 * adds frontend-only helpers/constants that don't exist on the Rust side.
 */

